#include <stdio.h>
#include <string.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    getchar(); // consume newline after T
    char buf[128];
    const char *prefix = "prod-";
    for (int i = 0; i < T; ++i) {
        if (!fgets(buf, sizeof(buf), stdin)) break;
        size_t len = strlen(buf);
        if (len && buf[len-1] == '\n') buf[--len] = '\0';
        if (len >= 5 && strncmp(buf, prefix, 5) == 0)
            printf("True\n");
        else
            printf("False\n");
    }
    return 0;
}

